parameters.jsCode:
// Gemini yanıtından script verisini çıkar
const geminiResponse = $input.first().json;

let scriptData;
try {
  // Gemini yanıtından metin içeriğini al
  const textContent = geminiResponse.candidates[0].content.parts[0].text;
  scriptData = JSON.parse(textContent);
} catch (e) {
  // JSON parse edilemezse ham metinden çıkarmaya çalış
  const rawText = geminiResponse.candidates?.[0]?.content?.parts?.[0]?.text || '';
  scriptData = {
    baslik: 'YouTube Shorts - ' + $('Verileri Ayarla').first().json.konu,
    aciklama: rawText.substring(0, 500),
    etiketler: ['shorts', 'türkçe', 'yapay zeka'],
    sahneler: [
      { sahne_no: 1, metin: rawText, gorsel_aciklama: 'Ana içerik', sure_saniye: 30 }
    ]
  };
}

// Tüm sahnelerin metinlerini birleştir
const tumMetin = scriptData.sahneler
  .map(s => `Sahne ${s.sahne_no}: ${s.metin}`)
  .join('\n\n');

// Video için metin overlay dosyası oluştur
const videoMetni = scriptData.sahneler
  .map(s => s.metin)
  .join('\n---\n');

return [{
  json: {
    baslik: scriptData.baslik,
    aciklama: scriptData.aciklama,
    etiketler: scriptData.etiketler || ['shorts'],
    sahneler: scriptData.sahneler,
    tumMetin: tumMetin,
    videoMetni: videoMetni,
    chatId: $('Verileri Ayarla').first().json.chatId,
    konu: $('Verileri Ayarla').first().json.konu,
    tarih: $('Verileri Ayarla').first().json.tarih
  }
}];

